import React, { useRef, useMemo, Suspense } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { Line } from "@react-three/drei";
import { EffectComposer, Bloom } from "@react-three/postprocessing";
import * as THREE from "three";
import "../style/NeuralNetwork3D.css";

/* ── Node data — 3 layers ── */
const NODES = [
  // Input (tech stack) — left
  { id: 0, label: "Python",     pos: [-2.2,  1.5,  0.1], color: "#60a5fa" },
  { id: 1, label: "PostgreSQL", pos: [-2.2,  0.5,  0.2], color: "#38bdf8" },
  { id: 2, label: "FastAPI",    pos: [-2.2, -0.5, -0.1], color: "#34d399" },
  { id: 3, label: "pandas",     pos: [-2.2, -1.5,  0.1], color: "#fbbf24" },
  // Processing — center
  { id: 4, label: "Pipeline",   pos: [ 0,    1.3,  0.3], color: "#e8b99a" },
  { id: 5, label: "API Layer",  pos: [ 0,    0.2, -0.4], color: "#d4a574" },
  { id: 6, label: "ML Engine",  pos: [ 0,   -0.7,  0.5], color: "#c49a7a" },
  { id: 7, label: "Scheduler",  pos: [ 0,   -1.6, -0.2], color: "#b4846c" },
  // Output — right
  { id: 8, label: "KPI",        pos: [ 2.2,  1.0,  0.0], color: "#4ade80" },
  { id: 9, label: "Predict",    pos: [ 2.2,  0,   -0.1], color: "#34d399" },
  { id: 10, label: "Reports",   pos: [ 2.2, -1.0,  0.1], color: "#86efac" },
];

const EDGES = [
  [0, 4], [0, 5], [0, 6],
  [1, 4], [1, 5],
  [2, 5],
  [3, 4], [3, 6], [3, 7],
  [4, 8], [4, 10],
  [5, 8], [5, 9],
  [6, 9],
  [7, 8], [7, 10],
];

// Subset of edges that carry animated signal particles
const SIGNAL_EDGES = EDGES.filter((_, i) => i % 2 === 0);

/* ── Glowing node (emissive sphere) ── */
function GlowNode({ pos, color }) {
  const ref = useRef();
  const phase = useRef(Math.random() * Math.PI * 2);
  useFrame(({ clock }) => {
    if (!ref.current) return;
    const s = 1 + Math.sin(clock.elapsedTime * 2.2 + phase.current) * 0.1;
    ref.current.scale.setScalar(s);
  });
  return (
    <mesh ref={ref} position={pos}>
      <sphereGeometry args={[0.1, 16, 16]} />
      <meshStandardMaterial
        color={color}
        emissive={color}
        emissiveIntensity={2.5}
        roughness={0.15}
        metalness={0.1}
      />
    </mesh>
  );
}

/* ── Edge line (animated opacity) ── */
function EdgeLine({ from, to }) {
  const phase = useRef(Math.random() * Math.PI * 2);
  const ref = useRef();
  const points = useMemo(() => [
    new THREE.Vector3(...from.pos),
    new THREE.Vector3(...to.pos),
  ], [from, to]);

  useFrame(({ clock }) => {
    if (!ref.current?.material) return;
    ref.current.material.opacity = 0.07 + Math.sin(clock.elapsedTime + phase.current) * 0.04;
  });

  return (
    <Line ref={ref} points={points} color="#6366f1" lineWidth={1} transparent opacity={0.07} />
  );
}

/* ── Signal particle traveling along an edge ── */
function SignalParticle({ nodeA, nodeB, color, speed = 0.35, offset = 0 }) {
  const ref = useRef();
  const t = useRef(offset % 1);

  const curve = useMemo(() => {
    const a   = new THREE.Vector3(...nodeA.pos);
    const b   = new THREE.Vector3(...nodeB.pos);
    const mid = new THREE.Vector3().addVectors(a, b).multiplyScalar(0.5)
      .add(new THREE.Vector3(0, 0.2, 0.12));
    return new THREE.CatmullRomCurve3([a, mid, b]);
  }, [nodeA, nodeB]);

  useFrame((_, delta) => {
    if (!ref.current) return;
    t.current = (t.current + delta * speed) % 1;
    ref.current.position.copy(curve.getPoint(t.current));
  });

  return (
    <mesh ref={ref}>
      <sphereGeometry args={[0.05, 8, 8]} />
      <meshStandardMaterial color={color} emissive={color} emissiveIntensity={3.5} roughness={0} />
    </mesh>
  );
}

/* ── Full scene ── */
function NetworkScene() {
  const groupRef = useRef();
  useFrame(({ clock }) => {
    if (!groupRef.current) return;
    groupRef.current.rotation.y = Math.sin(clock.elapsedTime * 0.14) * 0.28;
    groupRef.current.rotation.x = Math.sin(clock.elapsedTime * 0.09) * 0.06;
  });

  return (
    <group ref={groupRef}>
      <ambientLight intensity={0.04} />
      <pointLight position={[0, 2, 3]} intensity={0.4} color="#6366f1" />

      {EDGES.map(([a, b], i) => (
        <EdgeLine key={i} from={NODES[a]} to={NODES[b]} />
      ))}
      {NODES.map((n) => (
        <GlowNode key={n.id} pos={n.pos} color={n.color} />
      ))}
      {SIGNAL_EDGES.map(([a, b], i) => (
        <SignalParticle
          key={i}
          nodeA={NODES[a]}
          nodeB={NODES[b]}
          color={NODES[b].color}
          speed={0.28 + i * 0.04}
          offset={i * 0.18}
        />
      ))}
    </group>
  );
}

const NeuralNetwork3D = () => (
  <div className="nn3d-wrap">
    <div className="nn3d-header">
      <p className="nn3d-subtitle">Signal flows from raw tech inputs to analytics outputs</p>
    </div>
    <div className="nn3d-canvas" aria-hidden="true">
      <Canvas
        camera={{ position: [0, 0, 5.5], fov: 50 }}
        gl={{ antialias: true, alpha: false }}
        onCreated={({ gl }) => gl.setClearColor("#010108", 1)}
      >
        <Suspense fallback={null}>
          <NetworkScene />
          <EffectComposer>
            <Bloom luminanceThreshold={0.15} luminanceSmoothing={0.85} intensity={1.8} />
          </EffectComposer>
        </Suspense>
      </Canvas>
    </div>
    <div className="nn3d-legend">
      <div className="nn3d-legend-group"><span className="nn3d-dot" style={{ background: "#60a5fa" }} />Input</div>
      <div className="nn3d-legend-group"><span className="nn3d-dot" style={{ background: "#e8b99a" }} />Processing</div>
      <div className="nn3d-legend-group"><span className="nn3d-dot" style={{ background: "#4ade80" }} />Output</div>
    </div>
  </div>
);

export default NeuralNetwork3D;
